var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"하아, 이 등굣길도 오늘이 마지막이네......","JPN":"はぁ、この通学路も今日で最後だな……","ENG":"*Sigh* Today is our last day at school.","TWN":"唉，這條上學的路途今天是最後一次走了……"},"stage":{"bg":"STREET_SPRING","slots":{"L":null,"C":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"왜? 섭섭하기라도 해?","JPN":"どうしたの？　名残惜しい？","ENG":"Why? Are you sad?","TWN":"怎麼了？難道覺得遺憾嗎？"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"그야 당연하지, 반장!","JPN":"そりゃ当然だろ、委員長！","ENG":"Of course, Class President.","TWN":"當然啦，班長！"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"봄이 왔다고 꽃이 피는 땅은 이제 여기밖에 안 남았다며.","JPN":"春になって花が咲く土地は、もうここしか残ってないんだろ？","ENG":"This is the only place on Earth that still flowers in spring.","TWN":"到了春天仍會開花的土地就只剩下這裡了。"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"다른 생존지구들은 그나마 멀쩡한 곳도 위상 방벽 없인 숨쉬기도 위험하다던데......","JPN":"他の生存地区だって位相防壁がないと呼吸することすら危険らしいし……","ENG":"Other surviving sectors, even the most intact ones, are so contaminated that the people have to stay inside the phase barrier just to breathe.","TWN":"聽說其它倖存地區就算完好無損，也沒有地界屏障，在那裡連呼吸都很危險……"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"반장도 아쉽지 않아?","JPN":"委員長は名残惜しくないのか？","ENG":"Class President, aren't you sad?","TWN":"班長不覺得遺憾嗎？"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"매년 봄 소풍 전날만 되면 들떠서 잠도 못 자고 그랬던 것 같은데.","JPN":"毎年春の遠足の前日になると、楽しみで眠れなかったと思うけど。","ENG":"You were so excited to go on the spring picnic every year that you'd barely sleep the night before.","TWN":"我記得班長好像以往到了每年春天的遠足，前一晚都會興奮到睡不著覺的說。"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"그야 당연히 아쉽지.","JPN":"もちろん名残惜しいよ。","ENG":"Of course, I'm sad.","TWN":"當然遺憾啦。"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"아쉽긴 하지만......","JPN":"名残惜しいけど……","ENG":"I am, and...","TWN":"雖然遺憾……"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"그래도 괜찮아. 우리가 떠난다고 아카데미가 완전히 없어지는 건 아니잖아?","JPN":"でも大丈夫。私たちがここを去っても、アカデミーが完全になくなるわけじゃないでしょう？","ENG":"I'm not. We may be leaving, but the Academy will still be here, right?","TWN":"但沒關係。就算我們離開了，學校也不會不見啊？"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"졸업도 못 하고 전선으로 떠난 친구와 선생님들도 많은데, 우린 여기 남아서 학교 생활을 조금이라도 더 누리고 있는 거니까......","JPN":"卒業もできずに戦線に行った友達や先生も多い中で、\\n私たちはここで学校生活を楽しんでいるんだから……","ENG":"Many of our friends and teachers had to go out to fight before they could graduate, and we got to enjoy more days at school.","TWN":"有許多朋友和老師都沒有畢業就去了前線，我們卻能留在這兒，稍微多享受一會兒校園生活，所以……"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_SPRING_NULL","text":{"KOREA":"그것만으로도 난 감사한 마음이야.","JPN":"それだけでも私は感謝してる。","ENG":"I'm grateful just for that alone.","TWN":"光是擁有現在這樣…我已經滿懷感激了。"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"난 전선에 가는 것도 상관없어.","JPN":"俺は別に戦線に行ったって構わない。","ENG":"I don't mind going out to fight.","TWN":"雖然說…讓我上前線也無所謂。"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"하지만 여길 떠나면......","JPN":"でもここを離れたら……","ENG":"It's just that... if I leave this place...","TWN":"但是一旦離開了這裡…"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"아직 학교에 남아 있는 녀석들이랑은 언제 다시 보게 될지 모르니까.","JPN":"学校に残っているやつらといつまた会えるかわからないから。","ENG":"I might not be able to see the others in school anymore.","TWN":"我們和那些留在學校裡的同學們…也不知道什麼時候才能再見面…"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"조금 더 같이 지내는 것도 나쁘진 않은 것 같아.","JPN":"もう少し長く一緒にいるのも悪くないと思う。","ENG":"That's why I'd love to stay with them for a little longer.","TWN":"能和他們再多相處一段時光也很不錯啊。"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"......그런데 지금 들고 있는 거, 카메라 아냐?","JPN":"……ところで、今持ってるそれってカメラだろ？","ENG":"By the way, is that a camera in your hand?","TWN":"……呃，妳現在拿著的是攝影機嗎?"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOO_JIN_ALT_SPRING_NULL","text":{"KOREA":"어? 설마 그걸로 지금 나 찍고 있었어? 그런 거 아니지?","JPN":"え？　まさかそれで俺を撮ってたのか？　違うよな？","ENG":"Eh? Have you been filming me? Really?","TWN":"咦？？難道妳一直用攝影機在拍我嗎？不會吧？"},"stage":{"bg":"STREET_SPRING","slots":{"L":{"char_id":"YOO_JIN_ALT_SPRING_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_SPRING_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};